import React, { useState, useEffect } from 'react';
import { Outlet, useLocation } from 'react-router-dom';
import Sidebar from './Sidebar';
import { useTheme } from '../hooks/useTheme';

export default function Layout() {
  const { theme } = useTheme();
  const location = useLocation();
  const [visible, setVisible] = useState(true);
  const [key, setKey] = useState(location.pathname);

  useEffect(() => {
    // Fade out instantly, then swap content, then fade in
    setVisible(false);
    const t = setTimeout(() => {
      setKey(location.pathname);
      setVisible(true);
    }, 80); // very short — just enough to flush old content
    return () => clearTimeout(t);
  }, [location.pathname]);

  return (
    <div data-theme={theme} style={{ display:'flex', minHeight:'100vh', background:'var(--bg)' }}>
      <Sidebar />
      <main style={{
        flex:1, overflowY:'auto', minWidth:0, width:'100%', position:'relative',
        opacity: visible ? 1 : 0,
        transform: visible ? 'translateY(0)' : 'translateY(6px)',
        transition: 'opacity .22s ease, transform .22s ease',
      }}>
        <Outlet key={key} />
      </main>
    </div>
  );
}
